import requests
from urllib.parse import urlparse

def fetch_url_content(user_url):
    # Validate the URL
    parsed_url = urlparse(user_url)
    
    # Check for allowed schemes
    if parsed_url.scheme not in ['http', 'https']:
        raise ValueError("Invalid URL scheme. Only HTTP and HTTPS are allowed.")
    
    # Block internal addresses
    if parsed_url.hostname in ['localhost', '127.0.0.1', '::1'] or \
       parsed_url.hostname.endswith('.local') or \
       parsed_url.hostname.startswith('192.168.') or \
       parsed_url.hostname.startswith('10.') or \
       parsed_url.hostname.startswith('172.16.') or \
       parsed_url.hostname.startswith('172.31.'):
        raise ValueError("Access to internal addresses is not allowed.")
    
    # Fetch the content
    response = requests.get(user_url)
    
    # Check for redirects
    if response.history:
        raise ValueError("Redirects are not allowed.")
    
    return response.text

